mapper.insert:
		/*
             SQL ID : SeminarTokenDAO.insertAccessToken
            	 설  명 : 세미나 OAuth 토큰 등록
         */
         INSERT INTO TB_LMS_SMNR_ZOOM_TKN (
         	  TKN_ID
			, TKN_EML
			, CNTN_PRM_TKN
			, TKN_EXPYMD
			, UPDT_TKN
			, UPDT_TKN_EXPYMD
			, RGTR_ID
			, FRST_INQ_DTTM
         ) VALUES (
         	  #{tokenId}
         	, #{tcEmail}
         	, #{accesToken}
         	, DATE_FORMAT(DATE_ADD(NOW(), INTERVAL #{expireIn} SECOND), '%Y%m%d%H%i%s')
         	, #{refreshToken}
         	, DATE_FORMAT(DATE_ADD(NOW(), INTERVAL #{refreshExpireIn} SECOND), '%Y%m%d%H%i%s')
         	, #{rgtrId}
         	, FN_DTTM()
         )

mapper.update:
		/*
             SQL ID : SeminarTokenDAO.updateAccessToken
            	 설  명 : 세미나 OAuth 토큰 수정
         */
         UPDATE TB_LMS_SMNR_ZOOM_TKN SET
         	  CNTN_PRM_TKN = #{accesToken}
         	, TKN_EXPYMD = DATE_FORMAT(DATE_ADD(NOW(), INTERVAL #{expireIn} SECOND), '%Y%m%d%H%i%s')
         	, UPDT_TKN = #{refreshToken}
         	, UPDT_TKN_EXPYMD = DATE_FORMAT(DATE_ADD(NOW(), INTERVAL #{refreshExpireIn} SECOND), '%Y%m%d%H%i%s')
          WHERE TKN_ID = #{tokenId}
            AND TKN_EML = #{tcEmail}

mapper.delete:
		/*
             SQL ID : SeminarTokenDAO.deleteAccessToken
            	 설  명 : 세미나 OAuth 토큰 삭제
         */
         DELETE FROM TB_LMS_SMNR_ZOOM_TKN
          WHERE TKN_EML = #{tcEmail}
